use std::collections::HashMap;

struct Cache<T> {
    data: T,
}

trait LoaderAssociatedType<Error> {
    type LoadedData;
    fn load_data(key: &str) -> Result<Self::LoadedData, Error>;
}

struct ItemLoader;

impl LoaderAssociatedType<String> for ItemLoader {
    type LoadedData = HashMap<String, String>;
    fn load_data(key: &str) -> Result<Self::LoadedData, String> {
        if key.starts_with("fail_") {
            Ok(HashMap::from([(String::from("status"), String::from("failed"))]))
        } else {
            Err(format!("Unknown item key: {}", key))
        }
    }
}

fn process_item<L: LoaderAssociatedType<String>>(loader: &L, key: &str) -> Result<L::LoadedData, String> {
    L::load_data(key)
}

fn main() {
    let loader = ItemLoader;
    match process_item(&loader, "fail_network") {
        Ok(data) => println!("Successfully loaded data: {:?}", data),
        Err(e) => println!("Failed to load item: {}", e),
    }

    match process_item(&loader, "ok_save") {
        Ok(_) => {}, 
        Err(e) => println!("Expected failure on key: {}", e),
    }
}

use std::fmt::{self, Display};
use std::sync::Arc;

trait Event {
    fn get_data(&self) -> String;
}

struct PlayerMoveEvent {
    x: f32,
    y: f32,
}

impl Event for PlayerMoveEvent {
    fn get_data(&self) -> String {
        format!("PlayerMoved(x={}, y={})", self.x, self.y)
    }
}

struct ItemUseEvent {
    item_id: u32,
}

impl Event for ItemUseEvent {
    fn get_data(&self) -> String {
        format!("ItemUsed(id={})", self.item_id)
    }
}

trait ReplayStream<'a> {
    type AssociatedData;
    fn process_event(&self, event: &'a Self::AssociatedData) -> String;
}

struct Recorder {
    // This uses the concept of associated types to constrain what can be stored.
}

impl<'a> ReplayStream<'a> for Recorder {
    type AssociatedData = Box<dyn Event + 'a>;

    fn process_event(&self, event: &'a Self::AssociatedData) -> String {
        format!("Processing event: {}", event.get_data())
    }
}

fn main() {
    let recorder = Recorder {};

    let move_event = PlayerMoveEvent { x: 10.5, y: 22.1 };
    let item_event = ItemUseEvent { item_id: 42 };

    let recorded_move: Box<dyn Event> = Box::new(move_event);
    let recorded_item: Box<dyn Event> = Box::new(item_event);

    println!("n--- Playback Start ---");
    println!("Move playback result: {}", recorder.process_event(&recorded_move));
    println!("Item playback result: {}", recorder.process_event(&recorded_item));
}

use std::collections::HashMap;

trait Renderable<T>
where
    Self: Sized
{
    fn process(&self) -> T;
}

trait TemplateRenderer<R> where R: Renderable<String> + 'static {
    fn render_template(name: &str, context: HashMap<String, String>) -> Result<String, Box<dyn std::error::Error>>;
}

struct SimpleProcessor { _context: HashMap<String, String> }

impl Renderable<String> for SimpleProcessor {
    fn process(&self) -> String {
        format!("Processed successfully with context size: {}", self._context.len())
    }
}

struct ComplexProcessor { _metadata: String }

impl Renderable<String> for ComplexProcessor {
    fn process(&self) -> String {
        format!("Complex rendering done using metadata: {}", self._metadata)
    }
}

impl TemplateRenderer<SimpleProcessor> for SimpleProcessor {
    fn render_template(name: &str, context: HashMap<String, String>) -> Result<String, Box<dyn std::error::Error>> {
        let processor = SimpleProcessor { _context: context.clone() };
        let result = processor.process();
        Ok(format!("Template '{}' rendered to: {}", name, result))
    }
}

fn main() -> Result<(), Box<dyn std::error::Error>> {
    let mut context1 = HashMap::new();
    context1.insert("user".to_string(), "Alice".to_string());

    let result1 = SimpleProcessor::render_template("user_page", context1);
    println!("n--- Result 1 ---n{}", result1?);

    let mut context2 = HashMap::new();
    context2.insert("report".to_string(), "Q3".to_string());

    let result2 = SimpleProcessor::render_template("report", context2);
    println!("n--- Result 2 ---n{}", result2?);

    Ok(())
}

use std::fmt::{self, Display};
use std::error::Error;

struct JobContext {
    id: u32,
}

trait Runnable {
    type Output;
    fn run_with(&self, context: &JobContext) -> Result<Self::Output, Box<dyn Error>>;
}

struct ScheduledTask<T: Runnable> {
    job: T,
}

impl<T: Runnable + 'static> Display for ScheduledTask<T> {
    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
        write!(f, "Scheduled task defined for type {}", std::any::type_name::<T>())
    }
}

impl<T: Runnable + 'static> Runnable for ScheduledTask<T> {
    type Output = ();
    fn run_with(&self, context: &JobContext) -> Result<(), Box<dyn Error>> {
        let _result = self.job.run_with(context)?;
        println!("Successfully ran task associated with type {}", std::any::type_name::<T>());
        Ok(())
    }
}

struct PingJob;

impl Runnable for PingJob {
    type Output = ();
    fn run_with(&self, context: &JobContext) -> Result<Self::Output, Box<dyn Error>> {
        println!("Ping job executed successfully in context {}", context.id);
        Ok(())
    }
}

struct ComplexDataJob;

impl Runnable for ComplexDataJob {
    type Output = String;
    fn run_with(&self, context: &JobContext) -> Result<Self::Output, Box<dyn Error>> {
        println!("Complex data job executed successfully in context {}", context.id);
        Ok(format!("Processed result for job{}", context.id))
    }
}

fn main() -> Result<(), Box<dyn Error>> {
    let context = JobContext { id: 42 };

    let ping_task = ScheduledTask { job: PingJob };
    println!("{}", ping_task);
    ping_task.run_with(&context)?;

    let complex_task = ScheduledTask { job: ComplexDataJob };
    println!("{}", complex_task);
    complex_task.run_with(&context)?;

    Ok(())
}

use std::error::Error;
use std::fmt;
use std::any::Any;

struct PricingResult<T> { 
    value: f64,
    metadata: T
}

impl<T> fmt::Display for PricingResult<T> where T: fmt::Debug {
    fn fmt(&self, f: &mut fmt::Formatter) -> fmt::Result {
        write!(f, "Value: {}, Metadata: {:?}", self.value, self.metadata)
    }
}

struct DataPoint<T> { 
    input_data: T
}

fn process_batch<B>(items: Vec<B>) -> Result<Vec<PricingResult<()>>, Box<dyn Error>> where B: Into<Box<dyn Any + Send>> + Send + 'static {
    let mut results = Vec::new();
    for item in items {
        if let Some(data_box) = (item).into().downcast_ref::<f64>() {
            let result = PricingResult { 
                value: (*data_box * 1.5),
                metadata: () 
            };
            results.push(result);
        }
    }
    Ok(results)
}

fn main() -> Result<(), Box<dyn Error>> {
    let input_numbers: Vec<Box<dyn Any + Send + 'static>> = vec![ 
        Box::new(10.0),
        Box::new(20.0)
    ];

    match process_batch(input_numbers) {
        Ok(results) => {
            for result in results {
                println!("{}", result);
            }
        },
        Err(e) => {
            eprintln!("Failed to process batch: {}", e);
        }
    }

    Ok(())
}
